# Function to connect to Wi-Fi
def connect_wifi():
    print("Connecting to Wi-Fi...")
    sta_if = network.WLAN(network.STA_IF)
    sta_if.active(True)
    sta_if.connect(WIFI_SSID, WIFI_PASSWORD)
    while not sta_if.isconnected():
        time.sleep(1)
        print(".")
    print("Wi-Fi connected:", sta_if.ifconfig())
    return sta_if

